let globalLocale,
    namedLocale = {};

function setLocale() {
    if (arguments.length > 1) {
        let [name, locale] = arguments;
        namedLocale[name] = locale;
    } else {
        globalLocale = arguments[0];
    }
}

function getLocale(name) {
    return name ? namedLocale[name] : globalLocale;
}

export { setLocale, getLocale };
